<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">      &quot;npm&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;@ai-sdk/openai-compatible&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// OpenAI 兼容网关用这个适配器</span></span>
